import{_ as o,c as t,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新日志: 版本历史 | opencode-md-table-formatter","description":"了解 opencode-md-table-formatter 的版本演进和新功能。查看 v0.1.0 特性，包括自动格式化和宽度缓存等。","frontmatter":{"title":"更新日志: 版本历史 | opencode-md-table-formatter","sidebarTitle":"版本变化一览","subtitle":"更新日志：版本历史与变更记录","description":"了解 opencode-md-table-formatter 的版本演进和新功能。查看 v0.1.0 特性，包括自动格式化和宽度缓存等。","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"zh/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"zh/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),a={name:"zh/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(n,e,s,d,c,g){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="更新日志-版本历史与变更记录" tabindex="-1">更新日志：版本历史与变更记录 <a class="header-anchor" href="#更新日志-版本历史与变更记录" aria-label="Permalink to &quot;更新日志：版本历史与变更记录&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">学完你能做什么</p><ul><li>追踪插件的版本演进历程</li><li>了解每个版本的新功能和修复</li><li>掌握已知限制和技术细节</li><li>了解未来可能的功能增强</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><p>这是 opencode-md-table-formatter 的<strong>初始发布版本</strong>，包含以下核心功能：</p><ul><li><strong>自动表格格式化</strong>：通过 <code>experimental.text.complete</code> 钩子自动格式化 AI 生成的 Markdown 表格</li><li><strong>隐藏模式支持</strong>：计算宽度时正确处理隐藏的 Markdown 符号（如 <code>**</code>、<code>*</code>）</li><li><strong>嵌套 Markdown 处理</strong>：支持任意深度的嵌套 Markdown 语法，使用多遍剥离算法</li><li><strong>代码块保护</strong>：行内代码（<code>`code`</code>）内的 Markdown 符号保持字面形式，不参与宽度计算</li><li><strong>对齐方式支持</strong>：支持左对齐（<code>---</code> 或 <code>:---</code>）、居中对齐（<code>:---:</code>）、右对齐（<code>---:</code>）</li><li><strong>宽度缓存优化</strong>：缓存字符串显示宽度计算结果，提升性能</li><li><strong>无效表格验证</strong>：自动验证表格结构，无效表格会添加错误注释</li><li><strong>多字符支持</strong>：支持 Emoji、Unicode 字符、空单元格、超长内容</li><li><strong>静默错误处理</strong>：格式化失败不会中断 OpenCode 工作流</li></ul><h3 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h3><p>本版本包含约 <strong>230 行生产就绪的 TypeScript 代码</strong>：</p><ul><li><strong>12 个函数</strong>：职责清晰，分离良好</li><li><strong>类型安全</strong>：正确使用 <code>Hooks</code> 接口</li><li><strong>智能缓存清理</strong>：在操作数超过 100 次或缓存条目超过 1000 时触发清理</li><li><strong>多遍正则处理</strong>：支持任意嵌套深度的 Markdown 符号剥离</li></ul><div class="tip custom-block"><p class="custom-block-title">缓存机制</p><p>缓存设计用于优化重复内容的宽度计算。例如，当表格中多次出现相同的单元格文本时，只会计算一次宽度，后续直接从缓存读取。</p></div><h3 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h3><p>本版本不支持以下场景：</p><ul><li><strong>HTML 表格</strong>：仅支持 Markdown 管道表格（Pipe Table）</li><li><strong>多行单元格</strong>：不支持包含 <code>&lt;br&gt;</code> 标签的单元格</li><li><strong>无分隔行表格</strong>：表格必须包含分隔行（<code>|---|</code>）才能被格式化</li><li><strong>依赖要求</strong>：需要 <code>@opencode-ai/plugin</code> &gt;= 0.13.7（使用未公开的 <code>experimental.text.complete</code> 钩子）</li></ul><div class="info custom-block"><p class="custom-block-title">版本要求</p><p>插件依赖 OpenCode &gt;= 1.0.137 和 <code>@opencode-ai/plugin</code> &gt;= 0.13.7 才能正常工作。</p></div><hr><h2 id="未来计划" tabindex="-1">未来计划 <a class="header-anchor" href="#未来计划" aria-label="Permalink to &quot;未来计划&quot;">​</a></h2><p>以下功能计划在未来的版本中实现：</p><ul><li><strong>配置选项</strong>：支持自定义最小/最大列宽、禁用特定功能</li><li><strong>无表头表格支持</strong>：格式化没有表头行的表格</li><li><strong>性能优化</strong>：针对超大表格（100+ 行）的性能分析和优化</li><li><strong>更多对齐选项</strong>：扩展对齐方式的语法和功能</li></ul><div class="tip custom-block"><p class="custom-block-title">参与贡献</p><p>如果你有功能建议或想贡献代码，欢迎在 <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提出你的想法。</p></div><hr><h2 id="变更记录格式说明" tabindex="-1">变更记录格式说明 <a class="header-anchor" href="#变更记录格式说明" aria-label="Permalink to &quot;变更记录格式说明&quot;">​</a></h2><p>本项目的更新日志遵循 <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> 格式，版本号遵循 <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">语义化版本规范 (Semantic Versioning)</a>。</p><p><strong>版本号格式</strong>：<code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>：不兼容的 API 变更</li><li><strong>MINOR</strong>：向后兼容的新功能</li><li><strong>PATCH</strong>：向后兼容的问题修复</li></ul><p><strong>变更类型</strong>：</p><ul><li><strong>Added</strong>：新增功能</li><li><strong>Changed</strong>：现有功能的变更</li><li><strong>Deprecated</strong>：即将移除的功能</li><li><strong>Removed</strong>：已移除的功能</li><li><strong>Fixed</strong>：问题修复</li><li><strong>Security</strong>：安全相关修复</li></ul><hr><h2 id="建议阅读顺序" tabindex="-1">建议阅读顺序 <a class="header-anchor" href="#建议阅读顺序" aria-label="Permalink to &quot;建议阅读顺序&quot;">​</a></h2><p>如果你是新用户，建议按以下顺序学习：</p><ol><li><a href="./../../start/getting-started/">一分钟上手：安装与配置</a> —— 快速上手</li><li><a href="./../../start/features/">功能全览：自动格式化的魔法</a> —— 了解核心功能</li><li><a href="./../../faq/troubleshooting/">常见问题：表格没格式化怎么办</a> —— 故障排查</li><li><a href="./../../appendix/limitations/">已知限制：插件的边界在哪里</a> —— 了解限制</li></ol>',31)])])}const m=o(a,[["render",i]]);export{h as __pageData,m as default};
